import copy

def difference(d1, d2, level=-1):
    """
    Restituisce un dizionario con gli elementi di *d1* che non sono contenuti in *d2*.

    Il parametro *level* definisce la profondità massima della ricorsione. Per una ricorsione infinita, impostare *level* a -1. Per livello 1, se una chiave è presente sia in *d1* che in *d2* ma ha valori diversi, viene inclusa nella differenza. Consulta la funzione :func:`intersection` per ulteriori dettagli.

    *d1* e *d2* rimangono invariati. Tuttavia, *d1* o alcuni dei suoi sottodizionari potrebbero essere restituiti direttamente. Effettua una copia profonda (deep copy) del risultato quando appropriato.

    .. versione aggiunta:: 0.5
       Aggiunto il parametro *level*.
    """
    if level == 0:
        return {}

    diff = {}
    for key in d1:
        if key not in d2:
            diff[key] = copy.deepcopy(d1[key])
        elif isinstance(d1[key], dict) and isinstance(d2[key], dict) and (level == -1 or level > 1):
            sub_diff = difference(d1[key], d2[key], level - 1 if level != -1 else -1)
            if sub_diff:
                diff[key] = sub_diff
        elif d1[key] != d2[key]:
            diff[key] = copy.deepcopy(d1[key])

    return diff

def fill(self, coord, weight=1):
    """
    Riempie l'istogramma alla posizione *coord* con il peso specificato *weight*.
    """
    if coord in self.histogram:
        self.histogram[coord] += weight
    else:
        self.histogram[coord] = weight

import re
from typing import Dict, List, Union

class ValidationError(Exception):
    def __init__(self, messages: List[Dict[str, str]]):
        self.messages = messages
        super().__init__(str(messages))

def _validate_labels(labels: Dict[str, Union[str, List[str]]]) -> None:
    """
    Verifica che le chiavi e i valori nelle etichette fornite corrispondano alle rispettive espressioni regolari.

    ### Argomenti:
    - **labels (dict)**: il dizionario contenente le diverse etichette da validare.

    ### Eccezioni:
    - **ValidationError**: viene sollevata se una qualsiasi delle chiavi o dei valori delle etichette non corrisponde alla rispettiva espressione regolare. L'errore contiene come messaggio la lista di tutti gli errori che si sono verificati nelle etichette. Ogni elemento della lista è un dizionario con una coppia chiave-valore:
      - **key**: la chiave dell'etichetta o il valore dell'etichetta per cui si è verificato un errore, come stringa.
      - **value**: il messaggio di errore.
    """
    key_regex = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*$')
    value_regex = re.compile(r'^[a-zA-Z0-9_\-\.]+$')
    errors = []

    for key, value in labels.items():
        # Validate key
        if not isinstance(key, str):
            errors.append({str(key): 'expected string or bytes-like object'})
        elif not key_regex.match(key):
            errors.append({key: f"Label key '{key}' does not match the regex {key_regex.pattern}"})

        # Validate value
        if isinstance(value, list):
            for item in value:
                if not isinstance(item, str):
                    errors.append({str(item): 'expected string or bytes-like object'})
                elif not value_regex.match(item):
                    errors.append({item: f"Label value '{item}' does not match the regex {value_regex.pattern}"})
        else:
            if not isinstance(value, str):
                errors.append({str(value): 'expected string or bytes-like object'})
            elif not value_regex.match(value):
                errors.append({value: f"Label value '{value}' does not match the regex {value_regex.pattern}"})

    if errors:
        raise ValidationError(errors)

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Generates a default observer schema dictionary based on the provided manifest dictionary.

    Args:
        manifest_dict (dict): Partial Kubernetes resources.
        first_level (bool, optional): If True, indicates that the dictionary represents the entire observer_schema of a Kubernetes resource.

    Returns:
        dict: The generated partial observer_schema.
    """
    observer_schema = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            observer_schema[key] = generate_default_observer_schema_list(value)
        else:
            if first_level and key in ['apiVersion', 'kind', 'metadata']:
                observer_schema[key] = value
            else:
                observer_schema[key] = None

    return observer_schema

def generate_default_observer_schema_list(manifest_list):
    """
    Generates a default observer schema list based on the provided manifest list.

    Args:
        manifest_list (list): Partial Kubernetes resources in list format.

    Returns:
        list: The generated partial observer_schema.
    """
    observer_schema = []

    for item in manifest_list:
        if isinstance(item, dict):
            observer_schema.append(generate_default_observer_schema_dict(item))
        elif isinstance(item, list):
            observer_schema.append(generate_default_observer_schema_list(item))
        else:
            observer_schema.append(None)

    return observer_schema

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Insieme alla funzione :func:``update_last_applied_manifest_dict_from_resp``, 
    questa funzione viene chiamata ricorsivamente per aggiornare un 
    ``last_applied_manifest`` parziale a partire da una risposta parziale di Kubernetes.

    Argomenti:
        last_applied_manifest (list): ``last_applied_manifest`` parziale in fase di aggiornamento.
        observer_schema (list): ``observer_schema`` parziale.
        response (list): risposta parziale dall'API di Kubernetes.

    Questa funzione attraversa tutti i campi osservati e inizializza il loro valore 
    in ``last_applied_manifest`` se non sono ancora presenti.
    """
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append({})
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append([])
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        else:
            if i >= len(last_applied_manifest):
                last_applied_manifest.append(resp_item)

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Aggiorna un last_applied_manifest parziale a partire da una risposta parziale di Kubernetes.

    Args:
        last_applied_manifest (dict): last_applied_manifest parziale in fase di aggiornamento.
        observer_schema (dict): observer_schema parziale.
        response (dict): risposta parziale dall'API di Kubernetes.

    Raises:
        KeyError: Se il campo osservato non è presente nella risposta di Kubernetes.
    """
    for key, schema in observer_schema.items():
        if key not in response:
            raise KeyError(f"Campo osservato '{key}' non presente nella risposta di Kubernetes.")

        if isinstance(schema, dict):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = {}
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[key], schema, response[key])
        elif isinstance(schema, list):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = []
            update_last_applied_manifest_list_from_resp(last_applied_manifest[key], schema, response[key])
        else:
            if key not in last_applied_manifest:
                last_applied_manifest[key] = response[key]

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Aggiorna un last_applied_manifest parziale (lista) a partire da una risposta parziale di Kubernetes.

    Args:
        last_applied_manifest (list): last_applied_manifest parziale in fase di aggiornamento.
        observer_schema (list): observer_schema parziale.
        response (list): risposta parziale dall'API di Kubernetes.

    Raises:
        KeyError: Se il campo osservato non è presente nella risposta di Kubernetes.
    """
    for i, item in enumerate(response):
        if i >= len(last_applied_manifest):
            last_applied_manifest.append({})
        if isinstance(observer_schema[0], dict):
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[i], observer_schema[0], item)
        else:
            last_applied_manifest[i] = item

def generate_default_observer_schema(app):
    """
    Genera lo schema di osservazione predefinito per ogni risorsa Kubernetes presente in
    ``spec.manifest`` per la quale non è stato specificato uno schema di osservazione personalizzato.

    Argomenti:
        app (krake.data.kubernetes.Application): L'applicazione per la quale generare uno
            schema di osservazione predefinito.
    """
    default_schema = {
        "apiVersion": "v1",
        "kind": "ObserverSchema",
        "metadata": {
            "name": "default-observer-schema",
            "namespace": app.metadata.namespace
        },
        "spec": {
            "rules": [
                {
                    "apiGroups": ["*"],
                    "resources": ["*"],
                    "verbs": ["get", "list", "watch"]
                }
            ]
        }
    }

    for resource in app.spec.manifest:
        if not hasattr(resource, 'observer_schema'):
            resource.observer_schema = default_schema

    return app

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    formatted_sql = sql
    formatted_params = []

    for params in many_params:
        if isinstance(params, dict):
            # Convert named parameters to out style
            out_params = {f"out_{key}": value for key, value in params.items()}
            formatted_params.append(out_params)
        elif isinstance(params, (list, tuple)):
            # Convert ordinal parameters to out style
            out_params = [f"out_{i}" for i in range(len(params))]
            formatted_params.append(out_params)
        else:
            raise TypeError("params must be a Mapping or Sequence")

    return formatted_sql, formatted_params

