def get_logical_path_map(inventory, version):
    """
    Ottiene una mappa dei percorsi logici nello stato verso i file su disco per una determinata versione nell'inventario.

    Restituisce un dizionario: `logical_path_in_state -> set(content_files)`

    Il set di `content_files` può includere riferimenti a file duplicati presenti in versioni successive rispetto alla versione descritta.
    """
    logical_path_map = {}

    for logical_path, versions in inventory.items():
        if version in versions:
            content_files = set()
            for v in range(version, max(versions.keys()) + 1):
                if v in versions:
                    content_files.update(versions[v])
            logical_path_map[logical_path] = content_files

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    Convalida l'attributo fixty block nell'inventario.

    Controlla la struttura del blocco di fissità e assicurati che siano referenziati solo i file elencati nel manifesto.
    """
    if not isinstance(fixity, dict):
        raise ValueError("Il blocco di fissità deve essere un dizionario.")

    for file_name, checksum in fixity.items():
        if file_name not in manifest_files:
            raise ValueError(f"Il file '{file_name}' non è presente nel manifesto.")

        if not isinstance(checksum, str) or not checksum:
            raise ValueError(f"Il checksum per il file '{file_name}' deve essere una stringa non vuota.")

    return True

import os

def files_list(path):
    """
    Restituisce i file nel percorso `path`.
    """
    if not os.path.exists(path):
        raise FileNotFoundError(f"Path '{path}' does not exist.")

    if not os.path.isdir(path):
        raise NotADirectoryError(f"'{path}' is not a directory.")

    return [f for f in os.listdir(path) if os.path.isfile(os.path.join(path, f))]

def add_rendition(self, lang, file_path):
    """Add a new rendition of the document in a specific language.

    Args:
        lang (str): The language code for the rendition (e.g., 'en' for English).
        file_path (str): The file path to the rendition document.
    """
    if not hasattr(self, 'renditions'):
        self.renditions = {}
    self.renditions[lang] = file_path

def correggi_prefisso_namespace_w(contenuto):
    """
    Converte il testo che di default è 'w:st="' in 'w-st="'.
    """
    return contenuto.replace('w:st="', 'w-st="')

def absorb(self, args):
    """
    Dato un insieme `args` di espressioni, restituisce una nuova lista di espressioni applicando l'assorbimento e l'assorbimento negativo.

    Consulta https://en.wikipedia.org/wiki/Absorption_law

    Assorbimento::

        A & (A | B) = A, A | (A & B) = A

    Assorbimento negativo::

        A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    def apply_absorption(expr):
        if isinstance(expr, tuple):
            if expr[0] == '&':
                A, B = expr[1], expr[2]
                if isinstance(B, tuple) and B[0] == '|' and B[1] == A:
                    return A
                if isinstance(B, tuple) and B[0] == '|' and isinstance(B[1], tuple) and B[1][0] == '~' and B[1][1] == A:
                    return ('&', A, B[2])
            elif expr[0] == '|':
                A, B = expr[1], expr[2]
                if isinstance(B, tuple) and B[0] == '&' and B[1] == A:
                    return A
                if isinstance(B, tuple) and B[0] == '&' and isinstance(B[1], tuple) and B[1][0] == '~' and B[1][1] == A:
                    return ('|', A, B[2])
        return expr

    return [apply_absorption(expr) for expr in args]

def on(self, hook):
    """
    Funzione decorator per aggiungere un nuovo gestore al registro.

    Argomenti:
    - `hook` (HookType): Attributo del hook per il quale registrare il gestore.

    Restituisce:
    - `callable`: Decorator per registrare i listener per il hook specificato.
    """
    def decorator(func):
        if not hasattr(self, '_hooks'):
            self._hooks = {}
        if hook not in self._hooks:
            self._hooks[hook] = []
        self._hooks[hook].append(func)
        return func
    return decorator

def _fromutc(self, dt):
    if dt.tzinfo is not self:
        raise ValueError("dt.tzinfo is not self")

    # Convert the datetime to the new timezone
    new_dt = dt.astimezone(self)

    # Check if the datetime is ambiguous in the new timezone
    if self._is_ambiguous(new_dt):
        # If ambiguous, set the fold attribute accordingly
        new_dt = new_dt.replace(fold=1 if new_dt.fold else 0)

    return new_dt

def tzname_in_python2(namefunc):
    """
    Modifica l'output unicode in stringhe di byte in Python 2

    L'API tzname() è cambiata in Python 3. In precedenza restituiva stringhe di byte, ma è stata modificata per restituire stringhe unicode.
    """
    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)
        if isinstance(result, unicode):
            return result.encode('utf-8')
        elif isinstance(result, tuple):
            return tuple(item.encode('utf-8') if isinstance(item, unicode) else item for item in result)
        return result
    return wrapper

def get_versions():
    """
    Ottieni le informazioni sulla versione o restituisci il valore predefinito se non è possibile ottenerle.
    """
    import sys
    import platform
    import subprocess

    try:
        # Ottieni la versione di Python
        python_version = sys.version.split()[0]

        # Ottieni la versione del sistema operativo
        os_version = platform.platform()

        # Ottieni la versione di pip (se disponibile)
        try:
            pip_version = subprocess.check_output([sys.executable, '-m', 'pip', '--version']).decode().split()[1]
        except Exception:
            pip_version = "N/A"

        return {
            "python_version": python_version,
            "os_version": os_version,
            "pip_version": pip_version
        }
    except Exception:
        return {
            "python_version": "N/A",
            "os_version": "N/A",
            "pip_version": "N/A"
        }

def render(pieces, style):
    """
    Renderizzare i pezzi forniti nella versione richiesta dello stile.

    :param pieces: Lista di pezzi da renderizzare.
    :param style: Stile di renderizzazione richiesto.
    :return: Stringa rappresentante i pezzi renderizzati.
    """
    if style == "plain":
        return "\n".join(pieces)
    elif style == "html":
        return "<ul>\n" + "\n".join(f"<li>{piece}</li>" for piece in pieces) + "\n</ul>"
    elif style == "json":
        import json
        return json.dumps(pieces)
    else:
        raise ValueError(f"Stile non supportato: {style}")

def plus_or_dot(pezzi):
    """
    Restituisci un "+" se non è già presente, altrimenti restituisci un "."
    """
    if '+' not in pezzi:
        return '+'
    else:
        return '.'

def registra_gestore_vcs(vcs, metodo):  # decorator
    """Crea un decorator per contrassegnare un metodo come gestore di un VCS."""
    def decorator(func):
        if not hasattr(func, '_vcs_gestori'):
            func._vcs_gestori = {}
        func._vcs_gestori[vcs] = metodo
        return func
    return decorator

def next_version(version):
    """
    Prossimo identificatore di versione seguendo il modello esistente.

    Deve gestire sia versioni con prefisso zero che versioni senza prefisso zero.
    """
    # Split the version into parts
    parts = version.split('.')

    # Increment the last part
    last_part = int(parts[-1]) + 1

    # Handle the case where the last part overflows (e.g., 9 -> 10)
    if last_part > 9:
        parts[-1] = '0'
        if len(parts) > 1:
            parts[-2] = str(int(parts[-2]) + 1)
        else:
            parts.insert(0, '1')
    else:
        parts[-1] = str(last_part)

    # Reconstruct the version string
    return '.'.join(parts)

def deep_merge_nodes(nodes):
    from ruamel.yaml.nodes import MappingNode, ScalarNode

    merged_nodes = {}

    for key_node, value_node in nodes:
        key = key_node.value
        if key in merged_nodes:
            existing_value_node = merged_nodes[key]
            if isinstance(existing_value_node, MappingNode) and isinstance(value_node, MappingNode):
                # Deep merge the MappingNodes
                existing_mapping = {k.value: v for k, v in existing_value_node.value}
                new_mapping = {k.value: v for k, v in value_node.value}
                for k, v in new_mapping.items():
                    if k in existing_mapping and isinstance(existing_mapping[k], MappingNode) and isinstance(v, MappingNode):
                        # Recursively merge nested MappingNodes
                        existing_mapping[k] = deep_merge_nodes([(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v)])
                    else:
                        # Overwrite or add new key-value pair
                        existing_mapping[k] = v
                merged_nodes[key] = MappingNode(
                    tag='tag:yaml.org,2002:map',
                    value=[(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v) for k, v in existing_mapping.items()]
                )
            else:
                # Overwrite with the new value_node if not both are MappingNodes
                merged_nodes[key] = value_node
        else:
            # Add new key-value pair
            merged_nodes[key] = value_node

    return [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v] for k, v in merged_nodes.items()]

def parser_flags(parser):
    """
    Dato un'istanza di argparse.ArgumentParser, restituisce le sue opzioni (flag) 
    degli argomenti in una stringa separata da spazi.
    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dato un insieme di argomenti e un dizionario che associa il nome di un sottoparser a un'istanza di `argparse.ArgumentParser`, consente a ciascun sottoparser richiesto di tentare di analizzare tutti gli argomenti. Questo permette di condividere argomenti comuni, come "--repository", tra più sottoparser.

    Restituisce il risultato come una tupla composta da (un dizionario che associa il nome del sottoparser a uno spazio dei nomi di argomenti analizzati, una lista di argomenti rimanenti non gestiti da alcun sottoparser).
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    for subparser_name, parser in subparsers.items():
        try:
            args, remaining = parser.parse_known_args(remaining_args)
            parsed_args[subparser_name] = args
            remaining_args = remaining
        except SystemExit:
            # Ignore SystemExit exceptions raised by argparse when parsing fails
            continue

    return parsed_args, remaining_args

from ruamel.yaml.nodes import ScalarNode, MappingNode

def deep_merge_nodes(nodes):
    merged = {}

    for key_node, value_node in nodes:
        key = key_node.value

        if key in merged:
            existing_value_node = merged[key]

            if isinstance(existing_value_node, MappingNode) and isinstance(value_node, MappingNode):
                # Merge the MappingNodes
                existing_mapping = {k.value: v for k, v in existing_value_node.value}
                new_mapping = {k.value: v for k, v in value_node.value}

                # Deep merge the mappings
                for new_key, new_value in new_mapping.items():
                    if new_key in existing_mapping and isinstance(existing_mapping[new_key], MappingNode) and isinstance(new_value, MappingNode):
                        # Recursively merge nested MappingNodes
                        merged_nodes = deep_merge_nodes([
                            (ScalarNode(tag='tag:yaml.org,2002:str', value=new_key), existing_mapping[new_key]),
                            (ScalarNode(tag='tag:yaml.org,2002:str', value=new_key), new_value)
                        ])
                        existing_mapping[new_key] = merged_nodes[0][1]
                    else:
                        # Overwrite or add new key-value pair
                        existing_mapping[new_key] = new_value

                # Convert back to list of tuples
                merged[key] = MappingNode(
                    tag='tag:yaml.org,2002:map',
                    value=[(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v] for k, v in existing_mapping.items()
                )
            else:
                # If either value is not a MappingNode, the last value prevails
                merged[key] = value_node
        else:
            # If the key is not in the merged dict, just add it
            merged[key] = value_node

    # Convert the merged dict back to a list of tuples
    return [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v] for k, v in merged.items()]

def parser_flags(parser):
    """
    Dato un'istanza di argparse.ArgumentParser, restituisce i flag degli argomenti
    in una stringa separata da spazi.
    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dato un insieme di argomenti e un dizionario che associa il nome di un sottoparser a un'istanza di `argparse.ArgumentParser`, consente a ciascun sottoparser richiesto di tentare di analizzare tutti gli argomenti. Questo permette di condividere argomenti comuni, come "--repository", tra più sottoparser.

    Restituisce il risultato come una tupla composta da (un dizionario che associa il nome del sottoparser a uno spazio dei nomi analizzato degli argomenti, una lista di argomenti rimanenti non gestiti da alcun sottoparser).
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    for subparser_name, parser in subparsers.items():
        try:
            args, remaining = parser.parse_known_args(remaining_args)
            parsed_args[subparser_name] = args
            remaining_args = remaining
        except SystemExit:
            # Ignore SystemExit exceptions raised by argparse when parsing fails
            continue

    return parsed_args, remaining_args

def size_to_bytes(size: str) -> int:
    """
    Convertire una dimensione di file leggibile dall'uomo in byte.

    Il valore risultante è un'approssimazione poiché il valore di input è nella maggior parte dei casi arrotondato.

    Args:
        size: Una stringa che rappresenta una dimensione di file leggibile dall'uomo (es: '500K')

    Returns:
        Una rappresentazione decimale della dimensione del file

    Esempi::

        >>> size_to_bytes("500")
        500
        >>> size_to_bytes("1K")
        1000
    """
    size = size.strip().upper()
    if size[-1] in ['K', 'M', 'G', 'T']:
        num = float(size[:-1])
        unit = size[-1]
        if unit == 'K':
            return int(num * 1000)
        elif unit == 'M':
            return int(num * 1000 ** 2)
        elif unit == 'G':
            return int(num * 1000 ** 3)
        elif unit == 'T':
            return int(num * 1000 ** 4)
    else:
        return int(size)

def _dictsum(dicts):
    """
    Combina i valori dei dizionari forniti tramite l'iterabile `dicts`.

    >>> _dictsum([{'a': 1, 'b': 2}, {'a': 5, 'b': 0}])
    {'a': 6, 'b': 2}
    """
    result = {}
    for d in dicts:
        for key, value in d.items():
            if key in result:
                result[key] += value
            else:
                result[key] = value
    return result

def parser_flags(parser):
    """
    Dato un'istanza di `argparse.ArgumentParser`, restituisce i flag degli argomenti in una stringa separata da spazi.  
    Args:
        parser: istanza di `argparse.ArgumentParser`

    Returns:
        flag degli argomenti in una stringa separata da spazi
    """
    flags = []
    for action in parser._actions:
        if action.option_strings:
            flags.extend(action.option_strings)
    return ' '.join(flags)

from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    '''
    Converti un numero in una stringa utilizzando l'alfabeto fornito.

    L'output avrà la cifra più significativa per prima.
    '''
    if number < 0:
        raise ValueError("Il numero deve essere non negativo.")

    base = len(alphabet)
    if base == 0:
        raise ValueError("L'alfabeto non può essere vuoto.")

    if number == 0:
        return alphabet[0] if padding is None else alphabet[0].rjust(padding, alphabet[0])

    result = []
    while number > 0:
        remainder = number % base
        result.append(alphabet[remainder])
        number = number // base

    result.reverse()

    result_str = ''.join(result)

    if padding is not None:
        result_str = result_str.rjust(padding, alphabet[0])

    return result_str

def replace_dots(value, arg):
    """
    Sostituisce tutti i valori di '.' con arg nella stringa fornita
    """
    return value.replace('.', arg)

def subclasses(cls):
    """
    Restituisce tutte le sottoclassi di una classe, ricorsivamente.
    """
    def _subclasses(cls):
        for subclass in cls.__subclasses__():
            yield subclass
            yield from _subclasses(subclass)

    return list(_subclasses(cls))

def unquote(name):
    """
    Rimuovi le virgolette dal nome fornito.
    """
    return name.strip('"\'')

import re
from datetime import timedelta

def parse_frequency(frequency):
    """
    Dato un valore di frequenza sotto forma di stringa contenente un numero e un'unità di tempo,
    restituisci un'istanza corrispondente di datetime.timedelta o None se la frequenza è None o "always".

    Ad esempio, dato "3 weeks", restituisci datetime.timedelta(weeks=3).

    Genera un'eccezione ValueError se la frequenza fornita non può essere analizzata.
    """
    if frequency is None or frequency.lower() == "always":
        return None

    pattern = re.compile(r'^(\d+)\s*(second|minute|hour|day|week|month|year)s?$', re.IGNORECASE)
    match = pattern.match(frequency.strip())

    if not match:
        raise ValueError(f"Invalid frequency format: {frequency}")

    value = int(match.group(1))
    unit = match.group(2).lower()

    if unit == "second":
        return timedelta(seconds=value)
    elif unit == "minute":
        return timedelta(minutes=value)
    elif unit == "hour":
        return timedelta(hours=value)
    elif unit == "day":
        return timedelta(days=value)
    elif unit == "week":
        return timedelta(weeks=value)
    elif unit == "month":
        return timedelta(days=30 * value)  # Approximate month as 30 days
    elif unit == "year":
        return timedelta(days=365 * value)  # Approximate year as 365 days
    else:
        raise ValueError(f"Unsupported time unit: {unit}")

import os

def _resolve_string(matcher):
    """
    Ottieni il valore dall'ambiente dato un matcher che contiene un nome e un valore predefinito opzionale.  
    Se la variabile non è definita nell'ambiente e non viene fornito alcun valore predefinito, viene generato un errore.
    """
    name, *default = matcher.groups()
    if name in os.environ:
        return os.environ[name]
    elif default:
        return default[0]
    else:
        raise ValueError(f"Environment variable '{name}' is not defined and no default value is provided.")

import re

def get_pattern(pattern, strip=True):
    """
    Questo metodo converte la stringa fornita in un oggetto pattern regex
    """
    if strip:
        pattern = pattern.strip()
    return re.compile(pattern)

def _dump_string(obj, dumper=None):
    """
    Serializza in una stringa Unicode (Python 2) o in una stringa (Python 3).
    """
    if dumper is not None:
        return dumper(obj)
    if isinstance(obj, bytes):
        return obj.decode('utf-8')
    elif isinstance(obj, str):
        return obj
    else:
        return str(obj)

import logging
import os
import json
import yaml

def load_configurations(config_filenames, overrides=None, resolve_env=True):
    """
    Dato un elenco di nomi di file di configurazione, carica e valida ciascun file di configurazione.
    Restituisci i risultati come una tupla composta da:
    - un dizionario che associa il nome del file di configurazione alla corrispondente configurazione analizzata,
    - una sequenza di istanze di `logging.LogRecord` contenenti eventuali errori di analisi.
    """
    configurations = {}
    errors = []

    if overrides is None:
        overrides = {}

    for filename in config_filenames:
        try:
            with open(filename, 'r') as file:
                if filename.endswith('.json'):
                    config = json.load(file)
                elif filename.endswith('.yaml') or filename.endswith('.yml'):
                    config = yaml.safe_load(file)
                else:
                    raise ValueError(f"Unsupported file format: {filename}")

                # Apply overrides
                for key, value in overrides.items():
                    if key in config:
                        config[key] = value

                # Resolve environment variables if required
                if resolve_env:
                    for key, value in config.items():
                        if isinstance(value, str) and value.startswith('$'):
                            env_var = value[1:]
                            config[key] = os.getenv(env_var, value)

                configurations[filename] = config

        except Exception as e:
            error_msg = f"Error loading configuration from {filename}: {str(e)}"
            logging.error(error_msg)
            errors.append(logging.LogRecord(
                name=__name__,
                level=logging.ERROR,
                pathname=filename,
                lineno=0,
                msg=error_msg,
                args=None,
                exc_info=None
            ))

    return configurations, errors

def force_string(obj):
    """
    Questa funzione restituisce l'oggetto di tipo `bytes` corrispondente a ``obj`` nel caso in cui sia una stringa utilizzando UTF-8.
    """
    if isinstance(obj, str):
        return obj.encode('utf-8')
    return obj

def protocol_handlers(cls, protocol_version=None):
    """
    Restituisce un dizionario dei gestori di protocollo Bolt disponibili,
    indicizzati per tuple di versione. Se viene fornita una versione di protocollo
    esplicita, il dizionario conterrà zero o un elemento, a seconda che quella
    versione sia supportata o meno. Se non viene fornita alcuna versione di protocollo,
    verranno restituite tutte le versioni disponibili.

    :param protocol_version: tupla che identifica una specifica versione
        del protocollo (ad esempio, (3, 5)) oppure None
    :return: dizionario che associa una tupla di versione alla classe del gestore
        per tutte le versioni di protocollo rilevanti e supportate
    :raise TypeError: se la versione del protocollo non è passata come una tupla
    """
    # Dizionario di esempio che mappa le versioni del protocollo ai gestori
    available_handlers = {
        (3, 5): "HandlerForV3_5",
        (4, 0): "HandlerForV4_0",
        (4, 1): "HandlerForV4_1",
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("La versione del protocollo deve essere una tupla.")
        if protocol_version in available_handlers:
            return {protocol_version: available_handlers[protocol_version]}
        else:
            return {}
    else:
        return available_handlers

def _get_seq_with_type(seq, bufsize=None):
    """
    Restituisce una coppia (sequenza, tipo).  
    La sequenza è derivata da *seq*  
    (oppure è *seq*, se quest'ultima è di un tipo sequenza).
    """
    if isinstance(seq, (str, bytes, bytearray, list, tuple)):
        return seq, type(seq)
    else:
        return list(seq), list

def verifyClass(iface, candidate, tentative=False):
    """
    Verifica che il *candidate* possa fornire correttamente *iface*.
    """
    if not all(hasattr(candidate, attr) for attr in dir(iface) if not attr.startswith('__')):
        return False

    if not tentative:
        for attr in dir(iface):
            if not attr.startswith('__'):
                iface_attr = getattr(iface, attr)
                candidate_attr = getattr(candidate, attr)
                if not callable(iface_attr) and not callable(candidate_attr):
                    if iface_attr != candidate_attr:
                        return False
                elif callable(iface_attr) != callable(candidate_attr):
                    return False

    return True

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclasse a partire da una o più basi e da un'eventuale __metaclass__ esplicita.
    """
    if explicit_mc is not None:
        return explicit_mc
    for base in bases:
        if hasattr(base, '__class__'):
            return base.__class__
    return type

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, rimuove la chiave specificata e restituisce il valore corrispondente.  
    Se la chiave non viene trovata, viene restituito `d` se fornito, altrimenti viene sollevata un'eccezione KeyError.
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not __marker:
        return default
    else:
        raise KeyError(f"KeyError: {key}")

def popitem(self):
    """
    Rimuove e restituisce la coppia `(chiave, valore)` meno frequentemente utilizzata.
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")

    # Trova la chiave con il valore minimo (meno frequentemente utilizzata)
    min_key = min(self, key=self.get)
    value = self.pop(min_key)
    return (min_key, value)

def popitem(self):
    """
    Rimuove e restituisce la coppia `(chiave, valore)` meno recentemente utilizzata.
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")
    key = next(iter(self))
    value = self.pop(key)
    return (key, value)

def popitem(self):
    """
    Rimuovi e restituisci una coppia `(chiave, valore)` casuale.
    """
    if not self:
        raise KeyError("popitem(): dictionary is empty")
    key = next(iter(self))
    value = self.pop(key)
    return (key, value)

def _create_converter(self) -> _converting._Converter:
    """
    Crea il convertitore dello stile dei parametri.

    Restituisce il convertitore dello stile dei parametri (:class:`._converting._Converter`).
    """
    return _converting._Converter()

from enum import Enum

class RequestType(Enum):
    PUBLIC_MESSAGE = 1
    PRIVATE_MESSAGE = 2
    LEGACY_PAYLOAD = 3
    UNKNOWN = 4

def identify_request(request: RequestType) -> str:
    """
    Prova a identificare se si tratta di una richiesta Diaspora.

    Prova prima con un messaggio pubblico. Poi con un messaggio privato. Infine, verifica se si tratta di un payload legacy.
    """
    if request == RequestType.PUBLIC_MESSAGE:
        return "Richiesta Diaspora: Messaggio Pubblico"
    elif request == RequestType.PRIVATE_MESSAGE:
        return "Richiesta Diaspora: Messaggio Privato"
    elif request == RequestType.LEGACY_PAYLOAD:
        return "Richiesta Diaspora: Payload Legacy"
    else:
        return "Tipo di richiesta sconosciuto"

from datetime import datetime

def format_dt(dt):
    """
    Formatta un oggetto datetime nel modo in cui i nodi D* si aspettano.
    """
    if not isinstance(dt, datetime):
        raise ValueError("Input must be a datetime object")

    # Formato atteso dai nodi D*
    return dt.strftime("%Y-%m-%dT%H:%M:%S.%fZ")

def xml_children_as_dict(node):
    """
    Trasforma i figli del nodo <xml> in un dizionario, con chiavi basate sul nome del tag.

    Questa è una conversione superficiale - i nodi figli non vengono elaborati ricorsivamente.
    """
    result = {}
    for child in node:
        tag = child.tag
        if tag in result:
            if isinstance(result[tag], list):
                result[tag].append(child.text)
            else:
                result[tag] = [result[tag], child.text]
        else:
            result[tag] = child.text
    return result

import json
from urllib.parse import urljoin

def get_nodeinfo_well_known_document(url, document_path=None):
    """
    Genera un documento NodeInfo `.well-known`.

    Consulta la specifica: [http://nodeinfo.diaspora.software](http://nodeinfo.diaspora.software)

    :param url: L'URL base completo con protocollo, ad esempio `https://example.com`  
    :param document_path: Percorso personalizzato per il documento NodeInfo, se fornito (opzionale)  
    :returns: dict
    """
    if document_path is None:
        document_path = ".well-known/nodeinfo"

    well_known_url = urljoin(url, document_path)

    # Simulazione di un documento NodeInfo ben noto
    nodeinfo_document = {
        "links": [
            {
                "rel": "http://nodeinfo.diaspora.software/ns/schema/2.0",
                "href": urljoin(url, "nodeinfo/2.0")
            }
        ]
    }

    return nodeinfo_document

import json
from xml.etree import ElementTree as ET
from typing import Dict

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    Analizza il webfinger di Diaspora, che può essere in formato JSON (nuovo) o in formato XRD (vecchio).

    [https://diaspora.github.io/diaspora_federation/discovery/webfinger.html](https://diaspora.github.io/diaspora_federation/discovery/webfinger.html)
    """
    try:
        # Try to parse as JSON (new format)
        data = json.loads(document)
        return data
    except json.JSONDecodeError:
        # If JSON parsing fails, try to parse as XML (old format)
        try:
            root = ET.fromstring(document)
            namespaces = {'xrd': 'http://docs.oasis-open.org/ns/xri/xrd-1.0'}
            links = root.findall('xrd:Link', namespaces)
            result = {}
            for link in links:
                rel = link.get('rel')
                href = link.get('href')
                if rel and href:
                    result[rel] = href
            return result
        except ET.ParseError:
            # If both JSON and XML parsing fail, return an empty dict
            return {}

import requests

def send_document(url, data, timeout=10, method="post", *args, **kwargs):
    """
    Metodo di supporto per inviare un documento tramite POST.

    Gli ulteriori parametri ``*args`` e ``**kwargs`` saranno passati a ``requests.post``.

    :arg url: URL completo a cui inviare, incluso il protocollo  
    :arg data: Dizionario (sarà codificato come form), bytes o oggetto simile a un file da inviare nel corpo della richiesta  
    :arg timeout: Secondi di attesa per la risposta (predefinito: 10)  
    :arg method: Metodo da utilizzare, predefinito: post  
    :returns: Tupla contenente il codice di stato (int o None) e l'errore (istanza della classe di eccezione o None)
    """
    try:
        if method.lower() == "post":
            response = requests.post(url, data=data, timeout=timeout, *args, **kwargs)
        elif method.lower() == "put":
            response = requests.put(url, data=data, timeout=timeout, *args, **kwargs)
        else:
            raise ValueError(f"Unsupported method: {method}")

        response.raise_for_status()
        return (response.status_code, None)

    except requests.exceptions.RequestException as e:
        return (None, e)

def list_of_file_names(settings_dirs, spec_option):
    """
    Crea un nuovo tipo complesso IniType
    """
    import os
    file_names = []
    for directory in settings_dirs:
        if os.path.isdir(directory):
            for file in os.listdir(directory):
                if file.endswith(spec_option):
                    file_names.append(os.path.join(directory, file))
    return file_names

import yaml
from typing import Dict, Any

class IRValidatorException(Exception):
    pass

def validate_from_content(cls, spec_content=None) -> Dict[str, Any]:
    """
    Valida che il contenuto dello spec (YAML) contenga tutti i campi richiesti.

    :param spec_content: contenuto del file spec
    :raise IRValidatorException: quando i dati obbligatori
    sono mancanti nel file spec
    :return: Dizionario con i dati caricati da un file spec (YAML)
    """
    if spec_content is None:
        raise IRValidatorException("Il contenuto dello spec non può essere None.")

    try:
        spec_data = yaml.safe_load(spec_content)
    except yaml.YAMLError as e:
        raise IRValidatorException(f"Errore nel parsing del contenuto YAML: {e}")

    required_fields = ["field1", "field2", "field3"]  # Esempio di campi obbligatori

    for field in required_fields:
        if field not in spec_data:
            raise IRValidatorException(f"Campo obbligatorio mancante: {field}")

    return spec_data

def _include_groups(self, parser_dict):
    """
    Risolve la direttiva "include dict" nei file di specifica
    """
    if 'include' in parser_dict:
        for include_key in parser_dict['include']:
            if include_key in parser_dict:
                included_dict = parser_dict[include_key]
                for key, value in included_dict.items():
                    if key not in parser_dict:
                        parser_dict[key] = value
                    elif isinstance(value, dict) and isinstance(parser_dict[key], dict):
                        parser_dict[key].update(value)
                    elif isinstance(value, list) and isinstance(parser_dict[key], list):
                        parser_dict[key].extend(value)
        del parser_dict['include']
    return parser_dict

def get_spec_defaults(self):
    """
    Risolvere i valori degli argomenti dal file di specifica e da altre fonti.
    """
    # Assuming self.spec is a dictionary or similar structure that holds the specification
    defaults = {}
    if hasattr(self, 'spec'):
        for key, value in self.spec.items():
            if isinstance(value, dict) and 'default' in value:
                defaults[key] = value['default']
            else:
                defaults[key] = value
    return defaults

def get_deprecated_args(self):
    """
    Restituzione di un dizionario con opzioni che deprecano altre.
    """
    deprecated_args = {
        'old_arg1': 'new_arg1',
        'old_arg2': 'new_arg2',
        'old_arg3': 'new_arg3'
    }
    return deprecated_args

def validate_arg_deprecation(self, cli_args, answer_file_args):
    """
    Valida e stampa gli argomenti deprecati.

    :param cli_args: il dizionario degli argomenti dalla CLI
    :param answer_file_args: il dizionario degli argomenti dai file
    """
    deprecated_args = {
        'old_arg1': 'new_arg1',
        'old_arg2': 'new_arg2',
        # Aggiungi altri argomenti deprecati qui
    }

    for arg in cli_args:
        if arg in deprecated_args:
            print(f"Attenzione: L'argomento '{arg}' è deprecato. Usa '{deprecated_args[arg]}' invece.")

    for arg in answer_file_args:
        if arg in deprecated_args:
            print(f"Attenzione: L'argomento '{arg}' è deprecato. Usa '{deprecated_args[arg]}' invece.")

def get_parser_option_specs(self, command_name):
    """
    Ottiene tutte le opzioni per il comando specificato

    :param command_name: il nome del comando (main, virsh, ospd, ecc...)
    :return: la lista di tutte le opzioni del comando
    """
    if not hasattr(self, '_command_options'):
        self._command_options = {}

    if command_name in self._command_options:
        return self._command_options[command_name]

    # Simulate fetching options for the command
    # This is a placeholder implementation
    options = []
    if command_name == "main":
        options = ["--help", "--version", "--verbose"]
    elif command_name == "virsh":
        options = ["--connect", "--list", "--details"]
    elif command_name == "ospd":
        options = ["--config", "--log-level", "--output"]
    else:
        options = ["--option1", "--option2", "--option3"]

    self._command_options[command_name] = options
    return options

def get_option_spec(self, command_name, argument_name):
    """
    Ottiene la specifica per il nome dell'opzione specificato.
    """
    # Assuming self.options is a dictionary where keys are command names and values are dictionaries of argument specs
    if command_name in self.options:
        if argument_name in self.options[command_name]:
            return self.options[command_name][argument_name]
    return None

def validate_length_args(self, args):
    """
    Verifica se il valore degli argomenti non supera la lunghezza specificata.

    :param args: Gli argomenti ricevuti.
    """
    max_length = 100  # Esempio di lunghezza massima consentita
    for arg in args:
        if len(str(arg)) > max_length:
            raise ValueError(f"L'argomento {arg} supera la lunghezza massima consentita di {max_length} caratteri.")

def validate_choices_args(self, args):
    """
    Verifica se il valore degli argomenti di scelta è una delle opzioni disponibili.

    :param args: Gli argomenti ricevuti.
    """
    if not hasattr(self, 'choices'):
        raise AttributeError("No 'choices' attribute found in the class.")

    if not isinstance(self.choices, (list, tuple)):
        raise TypeError("'choices' must be a list or tuple.")

    if not args:
        raise ValueError("No arguments provided.")

    for arg in args:
        if arg not in self.choices:
            raise ValueError(f"Invalid choice: {arg}. Valid choices are: {self.choices}")

    return True

def validate_min_max_args(self, args):
    """
    Verifica se il valore degli argomenti è compreso tra i valori minimo e massimo.

    :param args: Gli argomenti ricevuti.
    """
    if not hasattr(self, 'min_value') or not hasattr(self, 'max_value'):
        raise AttributeError("min_value and max_value must be defined in the class.")

    for arg in args:
        if not (self.min_value <= arg <= self.max_value):
            raise ValueError(f"Argument {arg} is not between {self.min_value} and {self.max_value}.")
    return True

def get_nested_custom_and_control_args(self, args):
    """
    Suddivide gli argomenti di input in controlli nidificati e personalizzati.

    Argomenti di controllo: controllano il comportamento dell'IR. Questi argomenti
        non saranno inseriti nel file spec yml.
    Argomenti nidificati: sono utilizzati dai playbook di Ansible e saranno inseriti
        nel file spec yml.
    Argomenti personalizzati: variabili Ansible personalizzate da utilizzare al posto
        dell'uso normale degli argomenti nidificati.

    :param args: la lista raccolta di argomenti.
    :return: (dict, dict): dizionari piatti (control_args, nested_args)
    """
    control_args = {}
    nested_args = {}

    for key, value in args.items():
        if key.startswith('control_'):
            control_args[key] = value
        elif key.startswith('custom_'):
            nested_args[key] = value
        else:
            nested_args[key] = value

    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    Estende ``vars_dict`` con ``extra-vars``

    :param vars_dict: Dizionario in cui unire le extra-vars
    :param extra_vars: Lista di extra-vars
    """
    if extra_vars is not None:
        for key, value in extra_vars.items():
            vars_dict[key] = value
    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Converte gli argomenti nei tipi corretti modificando il parametro values_dict.

    Per impostazione predefinita, tutti i valori sono stringhe.

    :param parser_name: Il nome del comando, ad esempio main, virsh, ospd, ecc.
    :param values_dict: Il dizionario con gli argomenti
    """
    for key, value in values_dict.items():
        if isinstance(value, str):
            if value.lower() == 'true':
                values_dict[key] = True
            elif value.lower() == 'false':
                values_dict[key] = False
            elif value.isdigit():
                values_dict[key] = int(value)
            elif value.replace('.', '', 1).isdigit():
                values_dict[key] = float(value)
            elif value.lower() == 'none':
                values_dict[key] = None
    return values_dict
